async def execute_workflow(plan: TaskPlan):
    results = []
    for step in plan.steps:
        if step.type == 'api_call':
            response = await api_client.post(step.endpoint, json=step.payload)
            results.append({'status': 'success', 'step_id': step.idempotency_key})
        elif step.type == 'human_approval':
            await send_slack_approval(step.idempotency_key)
            await wait_for_approval(step.idempotency_key)
    if plan.requires_approval:
        await final_human_review(results)
    return results

import { z } from 'zod';
import { createInstructor } from '@instructor-ai/instructor';

const ActionSchema = z.object({
  type: z.enum(['api_call', 'human_approval', 'condition_check']),
  endpoint: z.string().optional(),
  payload: z.record(z.any()),
  idempotency_key: z.string()
});

const TaskPlanSchema = z.object({
  steps: z.array(ActionSchema).min(1).max(10),
  rollback_steps: z.array(ActionSchema).default([]),
  requires_approval: z.boolean().default(false)
});

const instructor = createInstructor({ mode: 'json' });

const taskPlan = await instructor.chat.completions.create({
  model: 'gpt-4o',
  schema: TaskPlanSchema,
  messages: [{ role: 'user', content: 'Plan workflow to update user profile' }]
});

interface WorkflowState {
  stepResults: Record<string, any>;
  completedSteps: string[];
  rollbackExecuted: boolean;
}

const redis = new Redis();

async function executeWorkflow(plan: TaskPlan): Promise<WorkflowState> {
  const state: WorkflowState = { stepResults: {}, completedSteps: [], rollbackExecuted: false };

  for (const step of plan.steps) {
    state.stepResults[step.idempotency_key] = await executeStep(step);
    state.completedSteps.push(step.idempotency_key);
    await redis.set(`workflow:${plan.id}`, JSON.stringify(state));
  }

  return state;
}

